   "HumanEval_160_do_algebra": {
      "category": "multipl",
      "difficulty": "medium",
      "source": "humaneval-js",
      "entry": "do_algebra",
      "signature": "function do_algebra(operator, operand)",
      "prompt": "Given two arrays operator, and operand. The first array has basic algebra operations, and \nthe second array is an array of integers. Use the two given arrays to build the algebric \nexpression and return the evaluation of this expression.\nThe basic algebra operations:\nAddition ( + ) \nSubtraction ( - ) \nMultiplication ( * ) \nFloor division ( // ) \nExponentiation ( ** ) \nExample:\noperator['+', '*', '-']\narray = [2, 3, 4, 5]\nresult = 2 + 3 * 4 - 5\n=> result = 9\nNote:\nThe length of operator array is equal to the length of operand array minus one.\nOperand is an array of of non-negative integers.\nOperator array has at least one operator, and operand array has at least two operands.",
      "tests": [
         {
            "args": [
               [
                  "**",
                  "*",
                  "+"
               ],
               [
                  2,
                  3,
                  4,
                  5
               ]
            ],
            "expected": 37
         },
         {
            "args": [
               [
                  "+",
                  "*",
                  "-"
               ],
               [
                  2,
                  3,
                  4,
                  5
               ]
            ],
            "expected": 9
         },
         {
            "args": [
               [
                  "//",
                  "*"
               ],
               [
                  7,
                  3,
                  4
               ]
            ],
            "expected": 8
         }
      ]
   },
